<?php
 namespace WPAICG\SEO\AIOSEO; use WP_Error; if (!defined('ABSPATH')) { exit; } function update_focus_keyword_logic(int $post_id, string $keyword): bool { if (empty($post_id) || !is_string($keyword)) { return false; } global $wpdb; $table_name = $wpdb->prefix . 'aioseo_posts'; $sanitized_keyword = sanitize_text_field($keyword); $keyphrases_data = []; $existing_row = null; $table_exists = ($wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s", $table_name)) === $table_name); if ($table_exists) { $existing_row = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$table_name} WHERE post_id = %d", $post_id)); if ($existing_row && !empty($existing_row->keyphrases)) { $keyphrases_data = json_decode($existing_row->keyphrases, true); if (json_last_error() !== JSON_ERROR_NONE) { $keyphrases_data = []; } } } $keyphrases_data['focus']['keyphrase'] = $sanitized_keyword; if (!isset($keyphrases_data['focus']['analysis'])) { $keyphrases_data['focus']['analysis'] = new \stdClass(); } if (!isset($keyphrases_data['additional'])) { $keyphrases_data['additional'] = []; } $db_update_success = true; if ($table_exists) { $keyphrases_json = wp_json_encode($keyphrases_data); if (is_wp_error($keyphrases_json)) { return false; } if ($existing_row) { $result = $wpdb->update( $table_name, ['keyphrases' => $keyphrases_json, 'updated' => current_time('mysql', 1)], ['post_id' => $post_id], ['%s', '%s'], ['%d'] ); } else { $result = $wpdb->insert( $table_name, [ 'post_id' => $post_id, 'keyphrases' => $keyphrases_json, 'created' => current_time('mysql', 1), 'updated' => current_time('mysql', 1), ], ['%d', '%s', '%s', '%s'] ); } $db_update_success = ($result !== false); } $meta_update_success = (update_post_meta($post_id, '_aioseo_keywords', $keyphrases_data) !== false); return $db_update_success && $meta_update_success; } 